<?php $__env->startSection('title','Order Details'); ?>
<?php $__env->startSection('content'); ?><div class="container py-5"><h1>Order <?php echo e($order->order_number); ?></h1><div class="row g-4"><div class="col-lg-8"><div class="table-card"><table class="table"><thead><tr><th>Product</th><th>Qty</th><th>Price</th><th>Total</th></tr></thead><tbody><?php $__currentLoopData = $order->items; $__env->addLoop($__currentLoopData); foreach($__currentLoopData as $item): $__env->incrementLoopIndices(); $loop = $__env->getLastLoop(); ?><tr><td><?php echo e($item->product_name); ?></td><td><?php echo e($item->quantity); ?></td><td>৳<?php echo e(number_format($item->unit_price,2)); ?></td><td>৳<?php echo e(number_format($item->total_price,2)); ?></td></tr><?php endforeach; $__env->popLoop(); $loop = $__env->getLastLoop(); ?></tbody></table></div></div><div class="col-lg-4"><div class="table-card"><p>Status: <span class="badge text-bg-info"><?php echo e($order->status); ?></span></p><p>Payment: <?php echo e(str_replace('_',' ',$order->payment->method)); ?> / <?php echo e($order->payment->status); ?></p><p>Delivery: ৳<?php echo e(number_format($order->delivery_charge,2)); ?></p><p>Discount: ৳<?php echo e(number_format($order->discount_amount,2)); ?></p><h4>Total: ৳<?php echo e(number_format($order->total_amount,2)); ?></h4><?php if(in_array($order->status,['pending','confirmed','processing'])): ?><form method="post" action="<?php echo e(route('orders.cancel',$order)); ?>"><?php echo csrf_field(); ?><button class="btn btn-outline-danger">Cancel Order</button></form><?php endif; ?></div></div></div></div><?php $__env->stopSection(); ?>

